INSERT INTO public.pandaa_knowledge (instruction, response, category, project) VALUES
('How do I apply for GKKIntern right now?', 'Apply through the GKKIntern internal portal and submit the required form. The team reviews applications in active batches.', 'Recruitment', 'GKKIntern'),
('Is GKKIntern currently active?', 'Yes, GKKIntern is currently running and accepting internship-related engagement. It is an active sub-company under Bubblesort.', 'Status', 'GKKIntern'),
('What is the internship duration at GKKIntern now?', 'The current internship duration is 1 month for the running program. Exact timelines are confirmed during onboarding.', 'Duration', 'GKKIntern'),
('Are GKKIntern internships only 1 month?', 'The currently running internship format is 1 month. Any future extensions are announced separately.', 'Duration', 'GKKIntern'),
('What is the selection flow for GKKIntern applicants?', 'The flow is form submission, screening call, and task round. Final selection is based on overall fit and task quality.', 'Process', 'GKKIntern'),
('What happens in the GKKIntern screening call?', 'The screening call checks your interest, readiness, and role fit. It also verifies your availability for the internship cycle.', 'Process', 'GKKIntern'),
('Is there a task round in GKKIntern hiring?', 'Yes, a task round is part of the selection process. It helps evaluate practical ability for the chosen track.', 'Process', 'GKKIntern'),
('Can freshers apply to GKKIntern programs?', 'Yes, freshers can apply if they match the role requirements. Performance in the process matters more than prior full-time experience.', 'Eligibility', 'GKKIntern'),
('Can students from non-tech backgrounds apply to GKKIntern?', 'Yes, non-tech students can apply for suitable tracks such as content, marketing, or operations. Role fit is evaluated during screening.', 'Eligibility', 'GKKIntern'),
('Does GKKIntern provide certificates?', 'Yes, completion certificates are provided after successful internship completion. Certificate eligibility depends on participation and performance.', 'Certification', 'GKKIntern'),
('Is stipend available in GKKIntern internships?', 'Stipend may be available depending on the assigned role and current internship policy. Details are shared during selection.', 'Compensation', 'GKKIntern'),
('Where should I send business queries for GKKIntern?', 'Send GKKIntern business queries to info@gkkintern.in. Include a clear subject and scope for faster response.', 'Contact', 'GKKIntern'),
('What is the official contact email for Bubblesort group queries?', 'The official group email is noreplay.gkk26@gmail.com. Use it for parent-level or general communication.', 'Contact', 'GKKIntern'),
('What is the official mobile number for GKKIntern support?', 'The official mobile number is +91 94775 64633. Share your name and query when contacting support.', 'Contact', 'GKKIntern'),
('Where is GKKIntern based?', 'GKKIntern operates from Kolkata, West Bengal, India. It is part of the Bubblesort ecosystem based in India.', 'Location', 'GKKIntern'),
('Does GKKIntern provide UI/UX Designer services?', 'Yes, UI/UX Designer is one of the currently running service areas. It includes practical product interface work.', 'Services', 'GKKIntern'),
('Does GKKIntern handle Dynamic Web and Application Development services?', 'Yes, Dynamic Web and Application Development is an active GKKIntern service line. It covers dynamic product builds and feature delivery.', 'Services', 'GKKIntern'),
('Does GKKIntern provide Full Stack services?', 'Yes, Full Stack service delivery is currently active under GKKIntern. It includes frontend, backend, and integration work.', 'Services', 'GKKIntern'),
